+
+// ServeFile replies to the request with the contents of the named file.
+func ServeFile(w ResponseWriter, r *Request, name string) {
+	f, err := os.Open(name)
+	if err != nil {
+		if os.IsNotExist(err) {
+			NotFound(w, r)
+		} else {
+			Error(w, "500 internal server error", StatusInternalServerError)
+		}
+		return
+	}
+	defer f.Close()
+
+	info, err := f.Stat()
+	if err != nil {
+		Error(w, "500 internal server error", StatusInternalServerError)
+		return
+	}
+	if info.IsDir() {
+		// Try index.html
+		indexPath := name + "/index.html"
+		if _, err := os.Stat(indexPath); err == nil {
+			ServeFile(w, r, indexPath)
+			return
+		}
+		NotFound(w, r)
+		return
+	}
+
+	data, err := io.ReadAll(f)
+	if err != nil {
+		Error(w, "500 internal server error", StatusInternalServerError)
+		return
+	}
+
+	ct := w.Header().Get("Content-Type")
+	if ct == "" {
+		ct = contentTypeByExtension(name)
+		if ct == "" {
+			ct = DetectContentType(data)
+		}
+	}
+	w.Header().Set("Content-Type", ct)
+	w.Header().Set("Content-Length", itoa(len(data)))
+	w.Write(data)
+}
+
+func contentTypeByExtension(name string) string {
+	ext := strings.ToLower(filepath.Ext(name))
+	switch ext {
+	case ".html", ".htm":
+		return "text/html; charset=utf-8"
+	case ".css":
+		return "text/css; charset=utf-8"
+	case ".js", ".mjs":
+		return "application/javascript; charset=utf-8"
+	case ".json":
+		return "application/json; charset=utf-8"
+	case ".xml":
+		return "text/xml; charset=utf-8"
+	case ".txt":
+		return "text/plain; charset=utf-8"
+	case ".png":
+		return "image/png"
+	case ".jpg", ".jpeg":
+		return "image/jpeg"
+	case ".gif":
+		return "image/gif"
+	case ".svg":
+		return "image/svg+xml"
+	case ".ico":
+		return "image/x-icon"
+	case ".woff":
+		return "font/woff"
+	case ".woff2":
+		return "font/woff2"
+	case ".pdf":
+		return "application/pdf"
+	case ".wasm":
+		return "application/wasm"
+	case ".webp":
+		return "image/webp"
+	case ".mp4":
+		return "video/mp4"
+	case ".webm":
+		return "video/webm"
+	case ".mp3":
+		return "audio/mpeg"
+	case ".ogg":
+		return "audio/ogg"
+	}
+	return ""
+}
