+
+func (f *fileHandler) ServeHTTP(w ResponseWriter, r *Request) {
+	path := r.URL.Path
+	if path == "" {
+		path = "/"
+	}
+	// Prevent path traversal
+	clean := filepath.Clean(path)
+	fullPath := f.root + clean
+	ServeFile(w, r, fullPath)
+}
